import java.util.TreeSet;

public class ScratchPad {
    private int n;
    private TreeSet<Integer> cars;

    public ScratchPad(int n) {
        this.n = n;
        cars = new TreeSet<Integer>();
    }

    public int add_car() {
        int carPosition = 0;
        if (!cars.isEmpty()) {
            int prev = -1, maxDist = -1;
            for (int pos : cars) {
                if (prev == -1) {
                    if (pos != 0) {
                        maxDist = pos;
                        carPosition = 0;
                    }
                } else {
                    int d = (pos - prev) / 2;
                    if (d > maxDist) {
                        maxDist = d;
                        carPosition = prev + d;
                    }
                }
                prev = pos;
            }
            if (n - 1 - prev > maxDist) {
                carPosition = n - 1;
            }
        }
        cars.add(carPosition);
        return carPosition;
    }

    public void remove_car(int p) {
        cars.remove(p);
    }

    public static void main(String[] args) {
        ScratchPad garage = new ScratchPad(10);

        // Test cases
        System.out.println("Car added at position: " + garage.add_car()); // Should add at position 0
        System.out.println("Car added at position: " + garage.add_car()); // Should add at position 9
        System.out.println("Car added at position: " + garage.add_car()); // Should add at position 5
        // Add more test cases as needed
    }
}

